#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005;
ll n,t,a[N],st[N][25],fa[N][25],fnum[N][25],lstans;
stack<int> sta;
int fun(int l,int r)
{
	int len=log2(r-l+1);
	if(st[l][len]>st[r-(1<<len)+1][len]) return st[l][len];
	else return st[r-(1<<len)+1][len];
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>t;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		st[i][0]=i;
		while(!sta.empty()&&a[sta.top()]<=a[i])
		{
			fa[sta.top()][0]=i;
			fnum[sta.top()][0]=(i-sta.top())*a[sta.top()];
			sta.pop();
		}
		sta.push(i);
	}
	while(!sta.empty())
	{
		fa[sta.top()][0]=n+1;
		sta.pop();
	}
	fa[n+1][0]=n+1;
	int MX=log2(n)+1;
	for(int j=1;j<=log2(n);j++)
	{
		for(int i=1;i<=n+1;i++)
		{
			if(a[st[i][j-1]]>a[st[i+(1<<(j-1))][j-1]]) st[i][j]=st[i][j-1];
			else st[i][j]=st[i+(1<<(j-1))][j-1];
			fa[i][j]=fa[fa[i][j-1]][j-1];
			fnum[i][j]=fnum[i][j-1]+fnum[fa[i][j-1]][j-1];
		}
	}
	while(t--)
	{
		int l,q;
		cin>>l>>q;
		l=1+(l^lstans)%n;
		q=1+(q^(lstans+1))%(n-l+1);
//		cout<<"l:" << l << "q:" << q <<endl;
		int mxnum=fun(l,l+q-1);
		ll ans=0;
		int pos=l;
		for(int i=log2(n);i>=0;i--)
		{
			if(fa[pos][i]<=mxnum)
			{
				ans+=fnum[pos][i];
				pos=fa[pos][i];
			}
		}
		ans+=(a[pos]*((l+q-1)-pos+1));
//		int mxnum=fun(l,l+q-1);
//		ll ans=0;
//		for(int i=log2(n);i>=0;i--)
//		{
//			if(fa[l][i]<=mxnum)
//			{
//				ans+=fnum[l][i];
//				l=fa[l][i];
//			}
//		}
//		ans+=(a[mxnum]*((l+q-1)-mxnum+1));
		lstans=ans;
		cout<<ans<<"\n";
	}
	return 0;
}
